INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-01352', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '關於定型化契約審閱期的敘述，下列何者正確？', '["定型化契約條款審閱期如有疑義時，應探求企業經營者之真意，不得拘泥於所用之文字", "企業經營者與消費者訂立定型化契約前，應有10日以內之合理期間，供消費者審閱全部條款內容", "企業經營者以定型化契約條款使消費者拋棄審閱權利者，雖非無效，但消費者得撤銷其意思表示", "違反審閱期規定者，其條款不構成契約之內容。但消費者得主張該條款仍構成契約之內容"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01353', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法規定，下列敘述何者正確？', '["企業經營者於商品或服務具有危害消費者生命、身體、健康、財產之可能者，未於明顯處為警告標示及緊 急處理危險之方法者應負賠償責任。但企業經營者能證明其無過失者，法院得減輕或免除其賠償責任", "商品或服務因其後有較佳之商品或服務，得被推定不符合當時科技或專業水準可合理期待之安全性", "從事經銷之企業經營者，改裝、分裝商品或變更服務內容者，視為從事設計、生產、製造商品或提供服務 之企業經營者", "企業經營者對消費者或第三人之損害賠償責任，得預先約定限制但不得約定免除"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01354', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '針對臺灣社會發生食品安全問題（如黑心油），消費者得依消費者保護法第50條所定消費者保護團體訴 訟（以下簡稱「消保團體訴訟」）尋求救濟。下列敘述何者正確？', '["多數受害之消費者得申請組成消保團體之組織，以便立即以團體自己名義，逕向法院提起消費者團體 損害訴訟", "消保團體於受讓20人以上消費者損害賠償請求權，得以自己名義提起訴訟。消費者於言詞辯論終結前， 不得終止讓與該損害賠償請求權", "消保團體依法提出消保團體訴訟者，應委任律師代理訴訟", "消保團體就消費者團體損害賠償訴訟，於扣除訴訟、支付予律師之必要費用以及得向消費者請求之報 酬後，將訴訟結果所得之賠償交付該讓與請求權之消費者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01355', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '企業經營者於下列違反消費者保護法之情形，何者所適用罰則所定之法定罰鍰額度為最高？', '["地方政府針對企業經營者提供之商品或服務，經調查認為確有損害消費者身體健康者，命其為限期回 收或其他必要處置，而企業經營者拒不遵從者", "企業經營者未依商品標示法等法令為商品或服務之標示", "企業經營者對消費者保證商品或服務之品質時，未主動出具書面保證書", "企業經營者使用定型化契約時，拒絕、規避或阻撓主管機關之派員查核"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01356', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法規定，定型化契約條款於下列何種情形，可認為並非違反平等互惠原則？', '["當事人間之給付與對待給付顯不相當者", "當事人一方之企業經營者，就系爭商品或服務之市場占有率規模超過50%者", "消費者負擔非其所能控制之危險者", "消費者違約時，應負擔顯不相當之賠償責任者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01357', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '甲於乙商店購得丙手機公司所生產之新型手機，甲交予其子丁使用，詎料丁於使用時竟發生手機電池燃 燒，致丁受傷送醫。依消費者保護法規定，關於本案中企業經營者責任之敘述，下列何者錯誤？', '["丙公司係生產問題手機之企業經營者，應確保該手機符合當時科技或專業水準可合理期待之安全性， 如有違反，應負損害賠償責任", "該問題手機雖係甲所購買，但如丁因使用而身體受損害，丙公司仍應對丁負損害賠償責任", "若丙公司能證明其於生產手機時無過失者，法院應免除其賠償責任", "經銷手機之乙商店，就使用問題手機所生損害，與丙公司連帶負損害賠償責任。但乙商店得主張對損 害之防免已盡相當之注意，或縱加以相當之注意而仍不免發生損害，以免除其與丙公司之連帶責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01358', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '關於公寓大廈住戶行為規範之敘述，下列何者錯誤？', '["住戶不得於大樓之公共密閉處所吸菸，以免影響其他住戶健康", "針對開放空間，在直轄市、縣（市）政府核准範圍內，住戶縱依規約或區分所有權人會議決議許可得使用該 空間，亦不得為營業目的使用", "住戶於公寓大廈內依法經營餐飲業者，應依中央主管機關所定保險金額投保公共意外責任保險", "住戶飼養動物，不得妨礙公共衛生、公共安寧及公共安全。但法令或規約另有禁止飼養之規定時，從其規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01359', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公寓大廈管理條例規定，區分所有權人召開定期會議之頻率為：', '["每半年至少應召開定期會議1次", "每季至少應召開定期會議1次", "每年至少應召開定期會議1次", "每兩年至少應召開定期會議1次"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01360', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '公寓大廈內連通數個專有部分之樓梯間，依公寓大廈管理條例相關規定屬於何種型態？', '["分別所有部分", "共同公共部分", "共用部分", "獨立部分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01361', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '關於公寓大廈起造人行為規範之敘述，下列何者錯誤？', '["起造人非經領得建造執照，不得辦理銷售", "起造人應就領得使用執照 1 年內之管理維護事項，提列一定比例金額作為公共基金，並於使用執照申 請時，繳交各地方主管機關公庫代收之證明", "起造人應移交公寓大廈共用部分及設施予管理委員會或管理負責人", "起造人得將法定停車空間讓售於特定人，以增加公共基金收入來源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
